package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getAllowMissingColumnNames());

        CSVFormat updated = original.withAllowMissingColumnNames();
        assertNotNull(updated);
        assertTrue(updated.getAllowMissingColumnNames());

        // Ensure original is not mutated (immutability)
        assertFalse(original.getAllowMissingColumnNames());

        // Calling again on updated returns a CSVFormat with allowMissingColumnNames true
        CSVFormat updatedAgain = updated.withAllowMissingColumnNames();
        assertSame(updated, updatedAgain, "Calling withAllowMissingColumnNames() on already allowed instance should return same instance");
    }
}
